try {
 Class.forName("sun.jdbc.odbc.JdbcOdbcDriver");
 String url = "jdbc:odbc:InventoryDB";
 Connection con = DriverManager.getConnection(url, "admin", "pass123");
 Statement stmt = con.createStatement();
 ResultSet rs = stmt.executeQuery("SELECT * FROM Products");

 while (rs.next()) {
 System.out.println(rs.getString("ProductName"));
 }

 rs.close();
 stmt.close();
 con.close();
} catch (Exception e) {
 e.printStackTrace();
}

Connection con = null;
try {
 Class.forName("sun.jdbc.odbc.JdbcOdbcDriver");
 con = DriverManager.getConnection("jdbc:odbc:OrderDB");
 con.setAutoCommit(false);

 Statement stmt = con.createStatement();
 stmt.executeUpdate("UPDATE Accounts SET balance = balance - 100 WHERE acc_id = 1");
 stmt.executeUpdate("UPDATE Accounts SET balance = balance + 100 WHERE acc_id = 2");

 con.commit();
} catch (SQLException e) {
 if (con != null) con.rollback();
 e.printStackTrace();
} finally {
 if (con != null) con.close();
}
